mapper.select:
/** UsptExpertDao.selectList */ select expert_id , expert_nm , gender_cd , fn_cmm_get_code_nm('GENDER', gender_cd) as gender_nm , native as native_yn , case when coalesce(native, false) = true then '내국인' else '외국인' end as native_nm , enc_brthdy , enc_mbtlnum , enc_email , wrc_nm , dept_nm , ofcps_nm , dty_nm , wrc_adres , wrc_adres_detail , wrc_adres_zip , wrc_telno , last_univ_nm , univ_dept_nm , act_realm_cd , attachment_group_id , expert_reqst_process_sttus_cd , creator_id , created_dt , updater_id , updated_dt , fn_cmm_get_code_nm('RCEPT_STTUS',expert_reqst_process_sttus_cd) as expert_reqst_process_sttus_nm /** 전문가신청처리상태명**/ , row_number() over (order by created_dt desc) as rn from uspt_expert where 1 = 1
and expert_id = #{expertId}
and expert_nm like '%' || #{expertNm} || '%'
and wrc_nm like '%' || #{wrcNm} || '%'
and enc_brthdy like = #{encBrthdy}
and enc_mbtlnum = #{encMbtlnum}
and enc_email = #{encEmail}
and expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}
and to_char(created_dt,'YYYYMMDD') between #{reqstDayStart} and #{reqstDayEnd}
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptExpertDao.selectListCount */ select count(expert_id) as cnt from uspt_expert where 1 = 1
and expert_id = #{expertId}
and expert_nm like '%' || #{expertNm} || '%'
and wrc_nm like '%' || #{wrcNm} || '%'

