mapper.select:
/** UsptExpertDao.selectListCount */
select count(expert_id) as cnt
  from uspt_expert
 where member_id = #{memberId}

/** UsptExpertDao.selectExpertReqstListCnt */
select  count(1)
from uspt_expert
 where 1 = 1

   		and expert_nm like '%' || #{expertNm} || '%'


   		and wrc_nm like '%' || #{wrcNm} || '%'


   		and expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}


		and to_char(created_dt,'YYYYMMDD') between #{reqstDayStart} and #{reqstDayEnd}

/** UsptExpertDao.getExpertReqstList */ select expert_id /** 전문가ID */ , expert_reqst_process_sttus_cd /*처리상태코드*/ , expert_nm /*전문가명*/ , gender_cd /*성별코드(G:GENDER) */ , native as native_yn /*내국인여부 */ , wrc_nm /*직장명*/ , ofcps_nm /**직위명 */ , created_dt /*신청일**/ from uspt_expert where 1 = 1
and expert_nm like '%' || #{expertNm} || '%'
and wrc_nm like '%' || #{wrcNm} || '%'
and expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}
and to_char(created_dt,'YYYYMMDD') between #{reqstDayStart} and #{reqstDayEnd}
offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.update:
	/** UsptExpertDao.updateExpertReqstReturn */
		update uspt_expert
			 set  expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}
			      , updater_id                = #{updaterId}
				  , updated_dt                = #{updatedDt}
        where  expert_id = #{expertId}

/** UsptExpertDao.update */
	update uspt_expert
		 set expert_nm                 = #{expertNm}
			, gender_cd                 = #{genderCd}
			, native                 	   = #{nativeYn}
			, enc_brthdy                = #{encBrthdy}
			, enc_mbtlnum               = #{encMbtlnum}
			, enc_email                 = #{encEmail}
			 ,wrc_nm                    = #{wrcNm}
			, dept_nm                   = #{deptNm}
			, ofcps_nm                  = #{ofcpsNm}
			, dty_nm                    = #{dtyNm}
			, wrc_adres                 = #{wrcAdres}
			, wrc_adres_detail          = #{wrcAdresDetail}
			, wrc_adres_zip             = #{wrcAdresZip}
			, wrc_telno                 = #{wrcTelno}
			, last_univ_nm              = #{lastUnivNm}
			, univ_dept_nm              = #{univDeptNm}
			, act_realm_cd              = #{actRealmCd}
			, attachment_group_id       = #{attachmentGroupId}
			, expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}
			, updater_id                = #{updaterId}
			, updated_dt                = #{updatedDt}
	where  expert_id = #{expertId}

mapper.delete:
/** UsptExpertDao.delete */
	delete from uspt_expert
	where  expert_id = #{expertId}
